<script setup>
import { computed } from 'vue';
import * as inlineFormattingModule from '@shared/inlineFormatting.js';

const { splitInlineTextWithPlaceholders } = inlineFormattingModule.default || inlineFormattingModule;

const props = defineProps({
  text: {
    type: String,
    default: '',
  },
  substitutions: {
    type: Object,
    default: () => ({}),
  },
  tag: {
    type: String,
    default: 'div',
  },
});

const segments = computed(() => splitInlineTextWithPlaceholders(props.text, props.substitutions));
</script>

<template>
  <component :is="tag" class="inline-text">
    <template v-for="(segment, index) in segments" :key="`${segment.type}-${index}`">
      <code v-if="segment.type === 'code'" class="inline-code">{{ segment.value }}</code>
      <span v-else>{{ segment.value }}</span>
    </template>
  </component>
</template>
