<script setup>
import { computed } from 'vue';

const props = defineProps({
  hasFeedback: Boolean,
  hintAvailable: Boolean,
  remainingHints: {
    type: Number,
    default: 0,
  },
  prefetching: Boolean,
  saving: Boolean,
  saveState: {
    type: String,
    default: 'idle',
  },
  saveMessage: {
    type: String,
    default: '',
  },
  queueDepth: {
    type: Number,
    default: 0,
  },
  canSubmit: {
    type: Boolean,
    default: true,
  },
  canShowSolution: {
    type: Boolean,
    default: true,
  },
  canReportCurrentDrill: {
    type: Boolean,
    default: true,
  },
  canGoPreviousDrill: {
    type: Boolean,
    default: false,
  },
  canGoNextDrill: {
    type: Boolean,
    default: true,
  },
  reportState: {
    type: String,
    default: 'idle',
  },
  reportMessage: {
    type: String,
    default: '',
  },
  reportButtonLabel: {
    type: String,
    default: 'Report drill',
  },
  currentPosition: {
    type: String,
    default: '',
  },
  progressPercent: {
    type: Number,
    default: 0,
  },
  drillMetadata: {
    type: Object,
    default: () => ({}),
  },
  feedback: {
    type: Object,
    default: null,
  },
  focusMode: Boolean,
  reviewMode: Boolean,
});

defineEmits(['submit', 'next', 'previous', 'report', 'hint', 'solution']);

const topicHeading = computed(() => {
  const metadata = props.drillMetadata || {};
  return metadata.topicTitle || metadata.topicDisplayName || metadata.topicName || metadata.topicId || 'AP CSA drill';
});

const primaryTags = computed(() => {
  const tags = props.drillMetadata?.tags || {};
  return {
    concept: tags.concept ?? '',
    difficulty: tags.difficulty ?? '',
    syntax: tags.syntax ?? '',
  };
});

const extraTags = computed(() => {
  const tags = props.drillMetadata?.tags || {};
  return Object.entries(tags)
    .filter(([key, value]) => value !== null && value !== undefined && String(value).trim() !== '' && !['concept', 'difficulty', 'syntax'].includes(key))
    .map(([key, value]) => ({ key, value }));
});
</script>

<template>
  <div
    class="practice-toolbar border rounded p-3 h-100 bg-body d-flex flex-column gap-3 transition-colors duration-300"
    :class="{
      'feedback-correct': feedback?.status === 'correct',
      'feedback-incorrect': feedback?.status === 'incorrect',
      'feedback-revealed': feedback?.status === 'revealed',
    }"
  >
    <!-- Progress Section -->
    <div v-if="!focusMode" class="progress-section">
      <div class="d-flex justify-content-between small text-body-secondary mb-1">
        <span class="fw-semibold">Progress</span>
        <span>{{ currentPosition }}</span>
      </div>
      <div class="progress session-progress" role="progressbar" :aria-valuenow="progressPercent" aria-valuemin="0" aria-valuemax="100" style="height: 6px;">
        <div class="progress-bar" :style="{ width: `${progressPercent}%` }"></div>
      </div>
    </div>

    <!-- Metadata Section -->
    <div v-if="!focusMode" class="metadata-section small border-bottom pb-3">
      <div class="metadata-heading mb-3">
        <div class="fw-bold" title="Topic" data-testid="topic-title">{{ topicHeading }}</div>
        <div class="text-body-secondary font-monospace mt-2" title="Drill ID" data-testid="drill-id">{{ props.drillMetadata?.drillId || 'Unknown drill' }}</div>
      </div>

      <div class="metadata-pair-grid">
        <div class="metadata-pair">
          <div class="text-uppercase text-body-secondary fw-bold mb-1" style="font-size: 0.7rem; letter-spacing: 0.05em;">Concept</div>
          <div class="fw-semibold">{{ primaryTags.concept || '—' }}</div>
        </div>
        <div class="metadata-pair">
          <div class="text-uppercase text-body-secondary fw-bold mb-1" style="font-size: 0.7rem; letter-spacing: 0.05em;">Difficulty</div>
          <div class="fw-semibold">{{ primaryTags.difficulty || '—' }}</div>
        </div>
        <div class="metadata-pair">
          <div class="text-uppercase text-body-secondary fw-bold mb-1" style="font-size: 0.7rem; letter-spacing: 0.05em;">Syntax</div>
          <div class="fw-semibold">{{ primaryTags.syntax || '—' }}</div>
        </div>
      </div>

      <div v-if="extraTags.length" class="mt-3 pt-2 border-top metadata-extra">
        <div v-for="tag in extraTags" :key="tag.key" class="d-flex justify-content-between gap-2 mb-1">
          <span class="text-body-secondary text-uppercase" style="font-size: 0.7rem; letter-spacing: 0.05em;">{{ tag.key }}</span>
          <span class="fw-semibold text-end">{{ tag.value }}</span>
        </div>
      </div>
    </div>

    <!-- Feedback Section (High-Alert Intensity 5) -->
    <div v-if="feedback" class="feedback-alert p-2 rounded border" :class="feedback.status">
      <div class="fw-bold d-flex align-items-center gap-2 text-uppercase" style="font-size: 0.85rem;">
        <span v-if="feedback.status === 'correct'">✅ Correct</span>
        <span v-else-if="feedback.status === 'incorrect'">❌ Incorrect</span>
        <span v-else-if="feedback.status === 'revealed'">🔍 Revealed</span>
      </div>
      <div class="small mt-1">{{ feedback.message }}</div>
    </div>

    <!-- Actions Section -->
    <div class="actions-section d-grid gap-2">
      <div class="fw-semibold small text-body-secondary mb-1">Actions</div>
      <button class="btn btn-primary" :disabled="!canSubmit" @click="$emit('submit')">Check Answer</button>
      <button class="btn btn-outline-secondary" :disabled="!canShowSolution" @click="$emit('solution')">Show Solution</button>
      <button class="btn btn-outline-secondary" :disabled="!hintAvailable" @click="$emit('hint')">
        {{ remainingHints > 0 ? `Show Hint (${remainingHints} left)` : 'No More Hints' }}
      </button>
      <div class="d-flex gap-2">
        <button class="btn btn-outline-primary flex-fill" :disabled="!canGoPreviousDrill" @click="$emit('previous')">Previous Drill</button>
        <button class="btn btn-outline-primary flex-fill" :disabled="!canGoNextDrill" @click="$emit('next')">Next Drill</button>
      </div>
      <button
        class="btn btn-sm mt-2"
        :class="{
          'btn-outline-danger': reportState === 'idle' || reportState === 'error',
          'btn-secondary': reportState === 'reporting',
          'btn-success': reportState === 'reported',
        }"
        title="Flag a drill that looks wrong so it can be reviewed and fixed."
        :disabled="!canReportCurrentDrill"
        @click="$emit('report')"
      >
        {{ reportButtonLabel }}
      </button>
      <div v-if="reportMessage" class="small" :class="{
        'text-body-secondary': reportState === 'idle',
        'text-danger': reportState === 'error',
        'text-success': reportState === 'reported',
        'text-success': reportState === 'reported',
        'text-primary': reportState === 'reporting',
      }">
        {{ reportMessage }}
      </div>
    </div>

    <!-- Session Status -->
    <div class="small text-body-secondary mt-auto pt-3 border-top">
      <div v-if="reviewMode" class="mb-1 text-uppercase fw-semibold" style="letter-spacing: 0.08em; font-size: 0.7rem;">
        Review mode
      </div>
      <div v-if="saveState === 'saving'">{{ saveMessage || 'Saving response...' }}</div>
      <div v-else-if="saveState === 'saved'">{{ saveMessage || 'Saved.' }}</div>
      <div v-else-if="saveState === 'error'">{{ saveMessage || 'Saving failed.' }}</div>
      <div v-else-if="queueDepth">Queued {{ queueDepth }} response{{ queueDepth === 1 ? '' : 's' }}.</div>
      <div v-else-if="prefetching">Preparing next slice...</div>
      <div v-else>Ready</div>
    </div>
  </div>
</template>

<style scoped>
.practice-toolbar {
  transition: background-color 0.3s ease, border-color 0.3s ease;
}

.feedback-correct {
  background-color: rgba(var(--bs-success-rgb), 0.1) !important;
  border-color: var(--bs-success-border-subtle) !important;
}

.feedback-incorrect {
  background-color: rgba(var(--bs-danger-rgb), 0.1) !important;
  border-color: var(--bs-danger-border-subtle) !important;
}

.feedback-revealed {
  background-color: rgba(var(--bs-info-rgb), 0.1) !important;
  border-color: var(--bs-info-border-subtle) !important;
}

.feedback-alert.correct { color: var(--bs-success-text-emphasis); }
.feedback-alert.incorrect { color: var(--bs-danger-text-emphasis); }
.feedback-alert.revealed { color: var(--bs-info-text-emphasis); }

.transition-colors {
  transition-property: background-color, border-color, color, fill, stroke;
  transition-timing-function: cubic-bezier(0.4, 0, 0.2, 1);
  transition-duration: 300ms;
}

.metadata-pair-grid {
  display: grid;
  gap: 0.75rem;
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

@media (max-width: 767.98px) {
  .metadata-pair-grid {
    grid-template-columns: 1fr;
  }
}

.metadata-heading {
  line-height: 1.25;
}
</style>
