<script setup>
const props = defineProps({
  modelValue: {
    type: Object,
    default: () => ({ unitIds: [], topicIds: [] }),
  },
  options: {
    type: Array,
    default: () => [],
  },
  loading: Boolean,
});

const emit = defineEmits(['update:modelValue', 'select-all', 'clear-all']);

function normalizeSelection(value = {}) {
  return {
    unitIds: Array.isArray(value.unitIds) ? [...new Set(value.unitIds.map((entry) => String(entry || '').trim()).filter(Boolean))] : [],
    topicIds: Array.isArray(value.topicIds) ? [...new Set(value.topicIds.map((entry) => String(entry || '').trim()).filter(Boolean))] : [],
  };
}

function updateSelection(nextSelection) {
  emit('update:modelValue', normalizeSelection(nextSelection));
}

function isUnitSelected(unitId) {
  return normalizeSelection(props.modelValue).unitIds.includes(unitId);
}

function isTopicSelected(topicId) {
  return normalizeSelection(props.modelValue).topicIds.includes(topicId);
}

function isTopicChecked(unitId, topicId) {
  return isUnitSelected(unitId) || isTopicSelected(topicId);
}

function toggleUnit(unitId) {
  const selection = normalizeSelection(props.modelValue);
  const unitIds = new Set(selection.unitIds);
  if (unitIds.has(unitId)) {
    unitIds.delete(unitId);
  } else {
    unitIds.add(unitId);
  }
  updateSelection({ ...selection, unitIds: [...unitIds] });
}

function toggleTopic(topicId) {
  const selection = normalizeSelection(props.modelValue);
  const topicIds = new Set(selection.topicIds);
  if (topicIds.has(topicId)) {
    topicIds.delete(topicId);
  } else {
    topicIds.add(topicId);
  }
  updateSelection({ ...selection, topicIds: [...topicIds] });
}

function unitLabel(unit) {
  return unit.unitName || unit.displayName || unit.unitId;
}

function topicLabel(topic) {
  return topic.topicName || topic.displayName || topic.topicId;
}
</script>

<template>
  <div>
    <div class="d-flex justify-content-between align-items-center mb-2">
      <label class="form-label fw-semibold mb-0">Units and Topics</label>
      <div class="btn-group btn-group-sm">
        <button class="btn btn-outline-secondary" @click="$emit('select-all')">All units</button>
        <button class="btn btn-outline-secondary" @click="$emit('clear-all')">None</button>
      </div>
    </div>

    <p class="text-muted small mb-3">
      Select a whole unit, or pick one or more topics within a unit. Whole-unit selections include every topic in that unit.
    </p>

    <div v-if="loading" class="text-muted small">Loading AP CSA units and topics...</div>
    <div v-else class="d-grid gap-3">
      <div
        v-for="unit in options"
        :key="unit.unitId"
        class="border rounded-3 p-3 bg-body"
      >
        <label class="d-flex justify-content-between align-items-start gap-3 mb-2">
          <span>
            <input
              class="form-check-input me-2"
              type="checkbox"
              :checked="isUnitSelected(unit.unitId)"
              @change="toggleUnit(unit.unitId)"
            />
            <span class="fw-semibold">{{ unitLabel(unit) }}</span>
          </span>
          <span class="badge text-bg-secondary-subtle">{{ unit.count || 0 }}</span>
        </label>

        <div class="ps-4 d-grid gap-2">
          <label
            v-for="topic in unit.topics || []"
            :key="topic.topicId"
            class="d-flex justify-content-between align-items-start gap-3"
          >
            <span>
              <input
                class="form-check-input me-2"
                type="checkbox"
                :checked="isTopicChecked(unit.unitId, topic.topicId)"
                :disabled="isUnitSelected(unit.unitId)"
                @change="toggleTopic(topic.topicId)"
              />
              <span>{{ topic.topicNumber ? `${topic.topicNumber} ${topicLabel(topic)}` : topicLabel(topic) }}</span>
            </span>
            <span class="badge text-bg-secondary-subtle">{{ topic.count || 0 }}</span>
          </label>
        </div>
      </div>
    </div>
  </div>
</template>
