<script setup>
import InlineText from './InlineText.vue';
import * as substitutionsModule from '@shared/substitutions.js';

const { stringifyStructuredValue } = substitutionsModule.default || substitutionsModule;

defineProps({
  drill: {
    type: Object,
    default: null,
  },
  revealedHints: {
    type: Array,
    default: () => [],
  },
  hintAvailable: Boolean,
  remainingHints: Number,
  solutionVisible: Boolean,
  solutionSnippets: {
    type: Array,
    default: () => [],
  },
});
</script>

<template>
  <section v-if="drill" class="drill-content mb-4">
    <!-- Prompt Area -->
    <div class="prompt-display mb-4">
      <div class="text-body-secondary small fw-bold text-uppercase mb-2" style="font-size: 0.7rem; letter-spacing: 0.05em;">
        Prompt
      </div>
      <div class="fs-5 lh-base">
        <InlineText :text="drill.promptTemplate" :substitutions="drill.substitutions || {}" />
      </div>
    </div>

    <!-- Hints Area -->
    <div v-if="revealedHints.length || hintAvailable" class="mt-4 pt-3 border-top">
      <div class="d-flex justify-content-between align-items-center mb-2">
        <div class="fw-bold small text-body-secondary text-uppercase" style="font-size: 0.7rem;">Hints</div>
        <div v-if="!revealedHints.length && hintAvailable" class="badge rounded-pill bg-body-tertiary text-body border">
          {{ remainingHints }} available
        </div>
      </div>
      
      <ul v-if="revealedHints.length" class="ps-3 mb-0">
        <li v-for="(hint, index) in revealedHints" :key="index" class="mb-2">
          <InlineText :text="stringifyStructuredValue(hint)" :substitutions="drill.substitutions || {}" tag="span" />
        </li>
      </ul>
    </div>

    <!-- Solution Area -->
    <div v-if="solutionVisible" class="mt-4 pt-3 border-top">
      <div class="fw-bold small text-body-secondary text-uppercase mb-2" style="font-size: 0.7rem;">Solution</div>
      <div v-if="solutionSnippets.length" class="d-grid gap-3">
        <div v-for="(snippet, index) in solutionSnippets" :key="index" class="p-3 bg-body-tertiary rounded border mono-block">
          <InlineText :text="stringifyStructuredValue(snippet)" :substitutions="drill.substitutions || {}" />
        </div>
      </div>
      <div v-else class="text-body-secondary italic small">No canonical solution snippet available.</div>
      <div class="text-body-secondary small mt-2">
        <i class="bi bi-info-circle me-1"></i> Solution revealed. This drill is marked as revealed, not solved.
      </div>
    </div>
  </section>
</template>

<style scoped>
.drill-content {
  color: var(--bs-body-color);
}

.mono-block {
  font-family: 'JetBrains Mono', 'Fira Code', monospace;
  font-size: 0.95rem;
}
</style>
