<script setup>
import { computed } from 'vue';

const props = defineProps({
  analytics: {
    type: Object,
    default: null,
  },
  loading: Boolean,
  previewMode: Boolean,
});

const accuracyLabel = computed(() => {
  const accuracy = props.analytics?.totals?.accuracy;
  if (accuracy === null || accuracy === undefined) {
    return 'Not enough data yet';
  }
  return `${Math.round(accuracy * 100)}%`;
});

const topStrengths = computed(() => props.analytics?.strengthSkills || []);
const topFocus = computed(() => props.analytics?.focusSkills || []);
const topGrowth = computed(() => props.analytics?.growthSkills || []);
</script>

<template>
  <div class="card panel-card h-100 border-0 shadow-sm">
    <div class="card-body p-4">
      <div class="d-flex justify-content-between align-items-start mb-3">
        <div>
          <div class="text-uppercase text-muted fw-bold small" style="letter-spacing: 0.08em;">
            {{ previewMode ? 'Preview momentum' : 'Your momentum' }}
          </div>
          <h2 class="h5 fw-bold mb-1">{{ analytics?.summaryLabel || (previewMode ? 'Preview progress stays in this browser' : 'Keep building your sample') }}</h2>
          <p class="text-muted small mb-0">
            {{ previewMode
              ? 'This card summarizes only the responses stored in this browser.'
              : analytics?.overallStatus === 'ready for review'
              ? 'A few skills look ready for a focused review.'
              : 'Keep practicing, and this area will have some information about how you are doing.' }}
          </p>
        </div>
        <span class="badge rounded-pill text-bg-body-tertiary border">{{ previewMode ? 'browser only' : (analytics?.overallConfidence || 'low') }}</span>
      </div>

      <div v-if="loading" class="text-muted small">Loading your study snapshot...</div>
      <template v-else-if="analytics">
        <div class="d-flex flex-wrap gap-2 mb-3">
          <span class="badge rounded-pill text-bg-primary-subtle text-primary border">
            {{ analytics?.totals?.attempts ?? 0 }} {{ previewMode ? 'preview responses' : 'responses' }}
          </span>
          <span class="badge rounded-pill text-bg-success-subtle text-success border">{{ accuracyLabel }}</span>
          <span class="badge rounded-pill text-bg-warning-subtle text-warning-emphasis border">
            {{ analytics?.totals?.skillCount ?? 0 }} {{ previewMode ? 'preview skills' : 'skills with data' }}
          </span>
        </div>

        <div class="mb-3">
          <div class="small text-uppercase text-muted fw-bold mb-2" style="letter-spacing: 0.08em;">Steady right now</div>
          <div v-if="topStrengths.length" class="d-grid gap-2">
            <div v-for="skill in topStrengths.slice(0, 3)" :key="skill.skillId" class="rounded border p-2 bg-body-tertiary">
              <div class="fw-semibold">{{ skill.displayName }}</div>
              <div class="text-muted small">{{ skill.status }} • {{ Math.round((skill.accuracy ?? 0) * 100) }}% accuracy</div>
            </div>
          </div>
          <div v-else class="text-muted small">Keep going. Once a few skills have enough data, we’ll start showing steady areas here.</div>
        </div>

        <div class="mb-3">
          <div class="small text-uppercase text-muted fw-bold mb-2" style="letter-spacing: 0.08em;">Good next review</div>
          <div v-if="topFocus.length" class="d-grid gap-2">
            <div v-for="skill in topFocus.slice(0, 3)" :key="skill.skillId" class="rounded border p-2 bg-body">
              <div class="fw-semibold">{{ skill.displayName }}</div>
              <div class="text-muted small">
                {{ skill.status }} • {{ skill.confidence }} confidence • {{ skill.attempts }} responses
              </div>
            </div>
          </div>
          <div v-else class="text-muted small">No review-heavy skills yet. That usually means you’re still building a good sample.</div>
        </div>

        <div>
          <div class="small text-uppercase text-muted fw-bold mb-2" style="letter-spacing: 0.08em;">Getting stronger</div>
          <div v-if="topGrowth.length" class="d-grid gap-2">
            <div v-for="skill in topGrowth.slice(0, 3)" :key="skill.skillId" class="rounded border p-2 bg-body">
              <div class="fw-semibold">{{ skill.displayName }}</div>
              <div class="text-muted small">{{ skill.trend }} • {{ skill.attempts }} responses</div>
            </div>
          </div>
          <div v-else class="text-muted small">No clear growth trend is standing out yet.</div>
        </div>
      </template>

      <div v-else class="text-muted small">
        {{ previewMode ? 'Try a few preview drills to build this browser’s momentum.' : 'Try some practice problems to build your momentum!' }}
      </div>
    </div>
  </div>
</template>
