<script setup>
import { nextTick, ref } from 'vue';

defineProps({
  modelValue: {
    type: String,
    default: '',
  },
  disabled: Boolean,
});

const emit = defineEmits(['update:modelValue', 'submit']);
const inputRef = ref(null);

function handleKeydown(event) {
  if ((event.ctrlKey || event.metaKey) && event.key === 'Enter') {
    event.preventDefault();
    emit('submit');
    return;
  }

  if (event.key !== 'Tab') {
    return;
  }

  event.preventDefault();
  const input = event.target;
  const start = input.selectionStart;
  const end = input.selectionEnd;
  const nextValue = `${input.value.slice(0, start)}  ${input.value.slice(end)}`;
  emit('update:modelValue', nextValue);
  nextTick(() => {
    input.selectionStart = start + 2;
    input.selectionEnd = start + 2;
  });
}

function focus() {
  inputRef.value?.focus();
}

defineExpose({
  focus,
});
</script>
<template>
  <div class="answer-editor">
    <textarea
      ref="inputRef"
      class="form-control mono-block"
      rows="8"
      :value="modelValue"
      :disabled="disabled"
      placeholder="Type a Java expression or statement here"
      @input="$emit('update:modelValue', $event.target.value)"
      @keydown="handleKeydown"
    />
    <div class="mt-2 text-muted small">
      Use <kbd>Ctrl</kbd> + <kbd>Enter</kbd> to check your answer.
    </div>
  </div>
</template>

<style scoped>
.answer-editor textarea {
  min-height: 150px;
  font-family: 'JetBrains Mono', 'Fira Code', monospace;
  font-size: 1rem;
}
</style>
