import * as regexModule from '@shared/regex.js';
import * as schemasModule from '@shared/drillSchemas.js';
import * as substitutionsModule from '@shared/substitutions.js';
import * as placeholderTypesModule from '@shared/placeholderTypes.js';
import { computed, ref, watch } from 'vue';

const { javaSnippetToRegex } = regexModule.default || regexModule;
const { detectPlaceholders, normalizeDrill, validateDrillPayload } = schemasModule.default || schemasModule;
const { applySubstitutions, generateSubstitutions } = substitutionsModule.default || substitutionsModule;
const { inferPlaceholderType } = placeholderTypesModule.default || placeholderTypesModule;

function createEmptyDrill() {
  return normalizeDrill({
    drillId: '',
    promptTemplate: '',
    placeholderTypes: {},
    skillCluster: '',
    tags: { difficulty: 'medium', syntax: 'expression', concept: 'access' },
    validationType: 'regex',
    correctPatterns: [],
    mistakePatterns: [],
    correctSnippets: [''],
    hintSequence: [],
    skills: [],
    notes: '',
    numReports: 0,
    sourceDrillId: '',
    sourceRowNumber: 0,
  });
}

export function useDrillEditor(randomizationBankRef) {
  const drill = ref(createEmptyDrill());
  const errors = ref({});
  const sampleSubstitutions = ref({});

  const placeholders = computed(() => detectPlaceholders(drill.value.promptTemplate));
  const regexPreviews = computed(() =>
    drill.value.correctSnippets.map((snippet) => (String(snippet || '').trim() ? javaSnippetToRegex(snippet) : ''))
  );
  const previewSnippets = computed(() =>
    drill.value.correctSnippets.map((snippet) => applySubstitutions(snippet, sampleSubstitutions.value))
  );

  function refreshPreview() {
    sampleSubstitutions.value = generateSubstitutions(drill.value.placeholderTypes, randomizationBankRef.value || {});
  }

  function loadDrill(input) {
    drill.value = normalizeDrill(input || createEmptyDrill());
    if (!drill.value.correctSnippets.length) {
      drill.value.correctSnippets = [''];
    }
    ensurePlaceholderTypes();
    refreshPreview();
  }

  function reset() {
    loadDrill(createEmptyDrill());
    errors.value = {};
  }

  function ensurePlaceholderTypes() {
    const next = { ...drill.value.placeholderTypes };
    placeholders.value.forEach((name) => {
      if (!next[name]) {
        next[name] = inferPlaceholderType(name, {
          promptTemplate: drill.value.promptTemplate,
          correctSnippets: drill.value.correctSnippets,
          correctPatterns: drill.value.correctPatterns,
          mistakePatterns: drill.value.mistakePatterns,
          hintSequence: drill.value.hintSequence,
          notes: drill.value.notes,
        });
      }
    });
    Object.keys(next).forEach((name) => {
      if (!placeholders.value.includes(name)) {
        delete next[name];
      }
    });
    drill.value.placeholderTypes = next;
  }

  function toPayload() {
    return {
      ...normalizeDrill(drill.value),
      correctSnippets: drill.value.correctSnippets.filter((snippet) => String(snippet || '').trim()),
      correctPatterns: regexPreviews.value.filter(Boolean),
    };
  }

  function validate() {
    const result = validateDrillPayload(drill.value);
    errors.value = result.errors;
    return result;
  }

  watch(
    () => drill.value.promptTemplate,
    () => {
      ensurePlaceholderTypes();
      refreshPreview();
    }
  );

  return {
    drill,
    errors,
    placeholders,
    previewSnippets,
    regexPreviews,
    loadDrill,
    reset,
    refreshPreview,
    validate,
    toPayload,
  };
}
