<script setup>
import { computed, nextTick, onMounted, ref, watch } from 'vue';
import apiClient from '../api/client';
import AnswerEditor from '../components/practice/AnswerEditor.vue';
import CourseUnitTopicPicker from '../components/practice/CourseUnitTopicPicker.vue';
import DrillReportModal from '../components/practice/DrillReportModal.vue';
import PracticeToolbar from '../components/practice/PracticeToolbar.vue';
import PromptCard from '../components/practice/PromptCard.vue';
import StudentMomentumCard from '../components/practice/StudentMomentumCard.vue';
import HelpModal from '../components/ui/HelpModal.vue';
import SessionCompleteModal from '../components/ui/SessionCompleteModal.vue';
import WelcomeModal from '../components/ui/WelcomeModal.vue';
import { useAppBootstrap } from '../composables/useAppBootstrap';
import { usePracticeSession } from '../composables/usePracticeSession';

const bootstrap = useAppBootstrap();
const session = usePracticeSession();
const answerEditorRef = ref(null);
const isPreviewTransport = import.meta.env.VITE_AUTODRILLS_TRANSPORT === 'preview';

const showHelp = ref(false);
const showWelcome = ref(isPreviewTransport);
const showReportModal = ref(false);
const showCompletionModal = ref(false);

const { targetSessionLength } = session;
const selectedPracticeScope = computed({
  get() {
    return session.selectedPracticeScope.value;
  },
  set(value) {
    session.selectedPracticeScope.value = value;
  },
});

const canStart = computed(() => (
  (selectedPracticeScope.value.unitIds.length > 0 || selectedPracticeScope.value.topicIds.length > 0)
  && !session.loadingBatch.value
));
const startButtonLabel = computed(() => (session.loadingBatch.value ? 'Fetching drills...' : 'Start Practice Session'));
const currentPosition = computed(() => {
  if (session.isReviewMode.value) {
    return `Review ${session.reviewIndex.value + 1} / ${session.completedDrillSnapshots.value.length}`;
  }
  if (session.sessionComplete.value) {
    return 'Session complete';
  }
  return session.hasActiveSession.value ? `${session.currentSessionAttemptOrdinal.value - 1} / ${targetSessionLength.value}` : 'No active session';
});
const progressPercent = computed(() => {
  if (session.isReviewMode.value) {
    const total = session.completedDrillSnapshots.value.length || 1;
    return Math.min(100, Math.round(((session.reviewIndex.value + 1) / total) * 100));
  }
  if (session.sessionComplete.value) {
    return 100;
  }
  if (!session.hasActiveSession.value) return 0;
  return Math.min(100, Math.round(((session.currentSessionAttemptOrdinal.value - 1) / targetSessionLength.value) * 100));
});
const selectedScopeSummary = computed(() => {
  const unitCount = selectedPracticeScope.value.unitIds.length;
  const topicCount = selectedPracticeScope.value.topicIds.length;
  if (!unitCount && !topicCount) {
    return 'None selected';
  }
  const unitLabel = unitCount === 1 ? '1 unit' : `${unitCount} units`;
  const topicLabel = topicCount === 1 ? '1 topic' : `${topicCount} topics`;
  if (unitCount && topicCount) {
    return `${unitLabel}, ${topicLabel} selected`;
  }
  return `${unitCount ? unitLabel : topicLabel} selected`;
});

function selectAllUnits() {
  selectedPracticeScope.value = {
    unitIds: bootstrap.availableCourseUnits.value.map((unit) => unit.unitId),
    topicIds: [],
  };
}

function clearScope() {
  selectedPracticeScope.value = { unitIds: [], topicIds: [] };
}

async function start() {
  showCompletionModal.value = false;
  await session.startPractice({ mode: 'normal' });
}

async function resetPreviewProgress() {
  if (!isPreviewTransport) {
    return;
  }
  const confirmed = typeof window === 'undefined' || window.confirm('Clear preview progress for this browser?');
  if (!confirmed) {
    return;
  }
  if (typeof apiClient.resetPreviewProgress === 'function') {
    await apiClient.resetPreviewProgress();
  }
  session.resetPracticeSession();
  await bootstrap.loadBootstrap(true);
  showHelp.value = false;
  showWelcome.value = false;
  showReportModal.value = false;
  showCompletionModal.value = false;
}

function openReportModal() {
  if (session.canReportCurrentDrill.value) {
    showReportModal.value = true;
  }
}

function closeReportModal() {
  showReportModal.value = false;
}

async function submitDrillReport(reportDetails) {
  const result = await session.reportCurrentDrill(reportDetails);
  if (result) {
    showReportModal.value = false;
  }
}

function changeTopics() {
  showCompletionModal.value = false;
  session.cancelAutoAdvance();
  session.resetPracticeSession();
}

async function focusAnswerEditor() {
  await nextTick();
  answerEditorRef.value?.focus?.();
}

const focusMode = ref(localStorage.getItem('practice-focus-mode') === 'true');

function toggleFocusMode() {
  focusMode.value = !focusMode.value;
  localStorage.setItem('practice-focus-mode', focusMode.value.toString());
  if (typeof window !== 'undefined') {
    window.dispatchEvent(new CustomEvent('autodrills-focus-mode-change', { detail: focusMode.value }));
  }
}

function formatTopicDisplay(drill = {}) {
  return [drill.topicNumber || drill.cedTopicNumber || '', drill.topicName || drill.topicId || ''].filter(Boolean).join(' ').trim();
}

function findTopicMetadata(topicId = '') {
  const normalizedTopicId = String(topicId || '').trim();
  if (!normalizedTopicId) {
    return {};
  }

  for (const unit of bootstrap.availableCourseUnits.value || []) {
    const topic = (unit.topics || []).find((entry) => String(entry.topicId || '').trim() === normalizedTopicId);
    if (topic) {
      return topic;
    }
  }

  return {};
}

const activeDrill = computed(() => session.viewDrill.value);

const drillMetadata = computed(() => {
  if (!activeDrill.value) return {};
  const topicMetadata = findTopicMetadata(activeDrill.value.topicId);
  const topicNumber = activeDrill.value.topicNumber || activeDrill.value.cedTopicNumber || topicMetadata.topicNumber || '';
  const topicName = activeDrill.value.topicName || topicMetadata.topicName || activeDrill.value.topicId || '';
  const topicTitle = [topicNumber, topicName].filter(Boolean).join(' ').trim();
  return {
    drillId: activeDrill.value.drillId,
    unitId: activeDrill.value.unitId || '',
    unitName: activeDrill.value.unitName || '',
    topicId: activeDrill.value.topicId || '',
    topicNumber,
    topicName,
    topicDisplayName: topicTitle || formatTopicDisplay(activeDrill.value),
    topicTitle: topicTitle || formatTopicDisplay(activeDrill.value),
    tags: activeDrill.value.tags,
  };
});

onMounted(async () => {
  await bootstrap.loadBootstrap();
});

watch(
  () => bootstrap.availableCourseUnits.value,
  (courseUnits) => {
    if (!selectedPracticeScope.value.unitIds.length && !selectedPracticeScope.value.topicIds.length && courseUnits.length) {
      selectedPracticeScope.value = {
        unitIds: courseUnits.map((unit) => unit.unitId),
        topicIds: [],
      };
    }
  },
  { immediate: true }
);

watch(
  () => session.hasActiveSession.value,
  (hasActiveSession, previousHasActiveSession) => {
    if (previousHasActiveSession && !hasActiveSession) {
      void bootstrap.loadBootstrap(true);
    }
  }
);

watch(
  () => session.sessionComplete.value,
  (complete) => {
    showCompletionModal.value = complete;
  },
  { immediate: true }
);

watch(
  () => activeDrill.value?.drillId || '',
  () => {
    showReportModal.value = false;
  }
);

// Focus is now handled by the transition's after-enter hook for reliability
watch(
  () => session.hasActiveSession.value,
  (active) => {
    if (active && !session.isReviewMode.value) {
      focusAnswerEditor();
    }
  }
);

function reviewCompletedSession() {
  showCompletionModal.value = false;
  showReportModal.value = false;
  session.enterLatestReviewSnapshot();
}

function practiceMore() {
  showCompletionModal.value = false;
  showReportModal.value = false;
  void start();
}

function goToTopicsList() {
  showCompletionModal.value = false;
  showReportModal.value = false;
  session.cancelAutoAdvance();
  session.resetPracticeSession();
}
</script>

<template>
  <div class="practice-page" :class="{ 'focus-mode': focusMode }">
    <HelpModal :show="showHelp" @close="showHelp = false" />
    <WelcomeModal
      :show="showWelcome"
      @close="showWelcome = false"
      @show-help="showWelcome = false; showHelp = true"
    />
    <SessionCompleteModal
      :show="showCompletionModal"
      :completed-count="session.completedDrillSnapshots.value.length"
      :total-count="targetSessionLength"
      @practice-more="practiceMore"
      @topics-list="goToTopicsList"
      @review-session="reviewCompletedSession"
    />
    <DrillReportModal
      :key="activeDrill?.drillId || 'no-drill'"
      :show="showReportModal"
      :drill="activeDrill"
      :preview-mode="isPreviewTransport"
      :submitting="session.viewReportState.value === 'reporting'"
      :error-message="session.viewReportState.value === 'error' ? session.viewReportMessage.value : ''"
      @close="closeReportModal"
      @submit="submitDrillReport"
    />

    <!-- Setup Mode Card -->
    <div v-if="!session.hasActiveSession.value" class="row g-4 align-items-start">
      <div class="col-lg-8">
        <div class="card panel-card shadow-sm border-0">
          <div class="card-body p-4">
            <div class="mb-4 d-flex justify-content-between align-items-start">
              <div>
                <h2 class="h4 fw-bold mb-1">Session Setup</h2>
                <p class="text-muted small mb-0">Choose the AP CSA units and topics you want to practice, then start a short drill set.</p>
              </div>
              <div class="d-flex align-items-center gap-2 ms-3">
                <button v-if="isPreviewTransport" class="btn btn-sm btn-outline-primary" @click="resetPreviewProgress">
                  Reset Preview Progress
                </button>
                <button class="btn btn-link text-muted p-0" title="Help" @click="showHelp = true">
                  <i class="bi bi-question-circle h5"></i>
                </button>
              </div>
            </div>

            <CourseUnitTopicPicker
              v-model="selectedPracticeScope"
              :options="bootstrap.availableCourseUnits.value"
              :loading="bootstrap.loading.value"
              @select-all="selectAllUnits"
              @clear-all="clearScope"
            />

            <div class="d-grid gap-2 mt-4 pt-3">
              <button class="btn btn-primary btn-lg" :disabled="!canStart" @click="start">
                {{ startButtonLabel }}
              </button>
            </div>

            <div class="mt-4 pt-3 border-top">
              <label for="sessionLengthSlider" class="form-label d-flex justify-content-between">
                <span class="fw-semibold text-muted">Target Session Length</span>
                <span class="badge bg-primary rounded-pill">{{ targetSessionLength }} drills</span>
              </label>
              <input 
                type="range" 
                class="form-range" 
                min="5" 
                max="50" 
                step="5" 
                id="sessionLengthSlider"
                v-model.number="targetSessionLength"
              >
            </div>

            <dl class="row mt-3 small mb-0 bg-body-tertiary p-3 rounded">
              <dt class="col-6 text-muted">Selection</dt>
              <dd class="col-6 text-end mb-0 fw-semibold">{{ selectedScopeSummary }}</dd>
            </dl>

            <div v-if="isPreviewTransport" class="alert alert-light border mt-4 mb-0 small">
              Reset clears this browser's preview progress only. It does not affect the full version.
            </div>
          </div>
        </div>
      </div>

      <div class="col-lg-4">
        <div class="sticky-top" style="top: 1rem; z-index: 100;">
          <StudentMomentumCard
            :analytics="bootstrap.studentAnalytics.value"
            :loading="bootstrap.loading.value && !bootstrap.studentAnalytics.value"
            :preview-mode="isPreviewTransport"
          />
        </div>
      </div>
    </div>

    <!-- Active Session View -->
    <div v-else class="session-container">
      <!-- Toolbar / Header -->
      <div class="d-flex justify-content-between align-items-center mb-4 pb-2 border-bottom">
        <div>
          <h1 class="h4 fw-bold mb-0">Practice</h1>
          <div class="small text-muted">Keep going.</div>
        </div>
        <div class="d-flex align-items-center gap-2">
          <button 
            class="btn btn-sm" 
            :class="focusMode ? 'btn-warning' : 'btn-outline-secondary'"
            title="Toggle Focus Mode"
            @click="toggleFocusMode"
          >
            <i class="bi" :class="focusMode ? 'bi-lightbulb-fill' : 'bi-lightbulb'"></i>
            <span class="ms-1 d-none d-md-inline">{{ focusMode ? 'Focused' : 'Focus Mode' }}</span>
          </button>
          <button class="btn btn-outline-secondary btn-sm" @click="changeTopics">Change scope</button>
          <button class="btn btn-sm btn-outline-secondary ms-1" title="Get Help" @click="showHelp = true">
            <i class="bi bi-question-circle"></i>
          </button>
        </div>
      </div>

      <div v-if="session.loadingBatch.value" class="text-center py-5">
        <div class="spinner-border text-primary" role="status"></div>
        <div class="mt-2 text-muted">Loading session...</div>
      </div>

      <template v-else-if="session.viewDrill.value">
        <Transition name="drill-fade-rise" mode="out-in" @after-enter="focusAnswerEditor">
          <div :key="session.viewDrill.value.drillId" class="row g-4">
            <!-- Main Content Column -->
            <div :class="focusMode ? 'col-lg-12' : 'col-lg-8'">
              <div class="card border-0 shadow-sm overflow-hidden mb-4">
                <div class="card-body p-4">
                  <PromptCard
                    :drill="session.viewDrill.value"
                    :revealed-hints="session.viewRevealedHints.value"
                    :hint-available="session.viewRemainingHints.value > 0"
                    :remaining-hints="session.viewRemainingHints.value"
                    :solution-visible="session.viewSolutionVisible.value"
                    :solution-snippets="session.solutionSnippets.value"
                  />

                  <div class="mt-4 pt-4 border-top">
                    <AnswerEditor
                      ref="answerEditorRef"
                      :model-value="session.viewCurrentInput.value"
                      :disabled="session.viewSubmittedThisDrill.value || session.isReviewMode.value"
                      @update:modelValue="session.currentInput.value = $event"
                      @submit="session.submitAnswer"
                    />
                  </div>
                </div>
              </div>
            </div>

            <!-- Sidebar Column -->
            <div v-if="!focusMode" class="col-lg-4">
              <div class="sticky-top" style="top: 1rem; z-index: 100;">
                <PracticeToolbar
                  :current-position="currentPosition"
                  :progress-percent="progressPercent"
                  :drill-metadata="drillMetadata"
                  :feedback="session.viewFeedback.value"
                  :focus-mode="focusMode"
                  :review-mode="session.isReviewMode.value"
                  :has-feedback="Boolean(session.viewFeedback.value)"
                  :hint-available="!session.isReviewMode.value && session.viewRemainingHints.value > 0"
                  :remaining-hints="session.viewRemainingHints.value"
                  :prefetching="session.prefetching.value"
                  :saving="session.saving.value"
                  :save-state="session.saveState.value"
                  :save-message="session.saveMessage.value"
                  :queue-depth="session.queueDepth.value"
                  :can-submit="session.canSubmitCurrentDrill.value"
                  :can-show-solution="session.canShowSolution.value"
                  :can-report-current-drill="session.canReportCurrentDrill.value"
                  :report-state="session.viewReportState.value"
                  :report-message="session.viewReportMessage.value"
                  :report-button-label="session.viewReportButtonLabel.value"
                  :can-go-previous-drill="session.hasPreviousReviewedDrill.value"
                  :can-go-next-drill="session.isReviewMode.value ? session.hasNextReviewedDrill.value : Boolean(session.viewFeedback.value)"
                  @submit="session.submitAnswer"
                  @hint="session.revealNextHint"
                  @solution="session.showSolution"
                  @next="session.nextDrill"
                  @previous="session.reviewPreviousDrill"
                  @report="openReportModal"
                />
              </div>
            </div>

            <!-- Focus Mode Actions (Fallback when sidebar hidden) -->
            <div v-if="focusMode" class="col-12 py-3 border-top d-flex justify-content-between align-items-center">
              <div class="d-flex gap-2">
                <button class="btn btn-primary btn-lg" :disabled="!session.canSubmitCurrentDrill.value" @click="session.submitAnswer">Check Answer</button>
                <button class="btn btn-outline-secondary" :disabled="session.isReviewMode.value || session.viewRemainingHints.value === 0" @click="session.revealNextHint">
                  Hint ({{ session.viewRemainingHints.value }} left)
                </button>
                <button
                  class="btn btn-sm"
                  :class="{
                    'btn-outline-danger': session.viewReportState.value === 'idle' || session.viewReportState.value === 'error',
                    'btn-secondary': session.viewReportState.value === 'reporting',
                    'btn-success': session.viewReportState.value === 'reported',
                  }"
                  :disabled="!session.canReportCurrentDrill.value"
                  title="Flag a drill that looks wrong so it can be reviewed and fixed."
                  @click="openReportModal"
                >
                  {{ session.viewReportButtonLabel.value }}
                </button>
              </div>
              <div class="d-flex gap-2">
                <button
                  class="btn btn-outline-primary btn-lg"
                  :disabled="!session.hasPreviousReviewedDrill.value"
                  @click="session.reviewPreviousDrill"
                >
                  Previous Drill
                </button>
                <button
                  class="btn btn-success btn-lg"
                  :disabled="session.isReviewMode.value ? !session.hasNextReviewedDrill.value : !session.viewFeedback.value"
                  @click="session.nextDrill"
                >
                  Next Drill →
                </button>
              </div>
            </div>
          </div>
        </Transition>
      </template>
    </div>
  </div>
</template>

<style scoped>
.practice-page {
  max-width: 1200px;
  margin: 0 auto;
}

.focus-mode {
  max-width: 900px;
}

.session-container {
  min-height: 80vh;
}

/* Ensure sticky sidebar behaves well */
.sticky-top {
  transition: all 0.3s ease;
}
</style>
