import { createRouter, createWebHashHistory, createWebHistory } from 'vue-router';
import PracticePage from './pages/PracticePage.vue';
import AdminDrillsPage from './pages/AdminDrillsPage.vue';
import TeacherAnalyticsPage from './pages/TeacherAnalyticsPage.vue';
import AboutPage from './pages/AboutPage.vue';
import UpgradePage from './pages/UpgradePage.vue';

const isPreviewTransport = import.meta.env.VITE_AUTODRILLS_TRANSPORT === 'preview';

const history = isPreviewTransport ? createWebHashHistory() : createWebHistory();

const previewRoutes = [
  { path: '/', redirect: '/practice' },
  { path: '/practice', component: PracticePage },
  { path: '/about', component: AboutPage },
  { path: '/upgrade', component: UpgradePage },
];

export default createRouter({
  history,
  routes: isPreviewTransport
    ? previewRoutes
    : [
        { path: '/', redirect: '/practice' },
        { path: '/practice', component: PracticePage },
        { path: '/about', component: AboutPage },
        { path: '/admin/drills', component: AdminDrillsPage },
        { path: '/admin/analytics', component: TeacherAnalyticsPage },
      ],
});
