<script setup>
import { computed, ref, watch } from 'vue';
import * as reportModule from '@shared/drillReports.js';
import {
  buildPreviewDrillReportPayload,
  buildPreviewIssueBody,
  buildPreviewIssueCopyText,
  buildPreviewIssueTitle,
  buildPreviewIssueUrl,
} from '../../lib/previewIssueReporting';

const { REPORT_ISSUE_AREAS } = reportModule.default || reportModule;

const props = defineProps({
  show: Boolean,
  drill: {
    type: Object,
    default: null,
  },
  submitting: Boolean,
  errorMessage: {
    type: String,
    default: '',
  },
  previewMode: Boolean,
});

const emit = defineEmits(['close', 'submit']);

const selectedAreas = ref([]);
const studentNote = ref('');
const localError = ref('');
const actionMessage = ref('');

const submitDisabled = computed(() => props.submitting || !selectedAreas.value.length);
const previewActionsDisabled = computed(() => props.submitting || !selectedAreas.value.length);
const hasPreviewIssueUrl = computed(() => Boolean(buildPreviewIssueUrl(buildPreviewPayload())));

function resetDraft() {
  selectedAreas.value = [];
  studentNote.value = '';
  localError.value = '';
  actionMessage.value = '';
}

watch(
  () => [props.show, props.drill?.drillId || ''],
  ([show]) => {
    if (show) {
      resetDraft();
    }
  },
  { immediate: true }
);

function toggleArea(area) {
  const index = selectedAreas.value.indexOf(area);
  if (index === -1) {
    selectedAreas.value = [...selectedAreas.value, area];
    return;
  }
  selectedAreas.value = selectedAreas.value.filter((entry) => entry !== area);
}

function buildPreviewPayload() {
  return buildPreviewDrillReportPayload({
    drill: props.drill || {},
    reportDetails: {
      issueAreas: selectedAreas.value,
      studentNote: studentNote.value,
    },
  });
}

function ensureSelectedAreas() {
  if (selectedAreas.value.length) {
    return true;
  }
  localError.value = 'Choose at least one issue area.';
  actionMessage.value = '';
  return false;
}

function submitReport() {
  if (!ensureSelectedAreas()) {
    return;
  }
  localError.value = '';
  emit('submit', {
    issueAreas: [...selectedAreas.value],
    studentNote: studentNote.value.trim(),
  });
}

async function copyPreviewDetails() {
  if (!ensureSelectedAreas()) {
    return;
  }

  const payload = buildPreviewPayload();
  const issueUrl = buildPreviewIssueUrl(payload);
  const copyText = buildPreviewIssueCopyText(payload);

  try {
    if (navigator.clipboard?.writeText) {
      await navigator.clipboard.writeText(copyText);
    } else {
      const textarea = document.createElement('textarea');
      textarea.value = copyText;
      textarea.setAttribute('readonly', 'true');
      textarea.style.position = 'fixed';
      textarea.style.opacity = '0';
      document.body.appendChild(textarea);
      textarea.select();
      document.execCommand('copy');
      document.body.removeChild(textarea);
    }
    actionMessage.value = issueUrl
      ? 'Report details copied. You can paste them into the GitHub issue if needed.'
      : 'Report details copied.';
    localError.value = '';
  } catch (error) {
    localError.value = error?.message || 'Copy failed.';
    actionMessage.value = '';
  }
}

function openPreviewIssue() {
  if (!ensureSelectedAreas()) {
    return;
  }

  const payload = buildPreviewPayload();
  const issueUrl = buildPreviewIssueUrl(payload);
  if (!issueUrl) {
    localError.value = 'Set VITE_AUTODRILLS_PREVIEW_ISSUES_URL or VITE_AUTODRILLS_PREVIEW_REPO to enable GitHub issue links.';
    actionMessage.value = '';
    return;
  }

  const opened = window.open(issueUrl, '_blank', 'noopener,noreferrer');
  if (!opened) {
    window.location.assign(issueUrl);
  }
  localError.value = '';
  actionMessage.value = 'GitHub issue opened in a new tab.';
}
</script>

<template>
  <Transition name="modal-fade">
    <div v-if="show" class="modal-backdrop" @click="$emit('close')">
      <div class="modal-dialog modal-dialog-centered" @click.stop>
        <div class="modal-content shadow-lg border-0 overflow-hidden">
          <div class="modal-header text-white border-0 py-3 px-4" style="background-color: #b42318;">
            <div>
              <h5 class="modal-title text-white mb-0">Report drill</h5>
              <div class="small text-white-50">Thanks for helping improve Autodrills.</div>
            </div>
            <button type="button" class="btn-close btn-close-white" :disabled="submitting" @click="$emit('close')"></button>
          </div>
          <div class="modal-body p-4">
            <p class="text-body-secondary mb-3">
              <span v-if="previewMode">Preview mode opens a prefilled GitHub issue in the public preview repo.</span>
              <span v-else>
                What seemed wrong about <span class="fw-semibold text-body">{{ drill?.drillId || 'this drill' }}</span>?
              </span>
            </p>

            <div class="row g-2 mb-3">
              <div v-for="area in REPORT_ISSUE_AREAS" :key="area.value" class="col-12 col-md-6">
                <label class="report-option d-flex align-items-center gap-2 rounded border p-2 h-100">
                  <input
                    :checked="selectedAreas.includes(area.value)"
                    class="form-check-input m-0"
                    type="checkbox"
                    :value="area.value"
                    :disabled="submitting"
                    @change="toggleArea(area.value)"
                  >
                  <span class="fw-semibold">{{ area.label }}</span>
                </label>
              </div>
            </div>

            <div class="mb-2">
              <label class="form-label fw-semibold" for="studentReportNote">Short note (optional)</label>
              <textarea
                id="studentReportNote"
                v-model="studentNote"
                class="form-control"
                :disabled="submitting"
                maxlength="280"
                rows="3"
                placeholder="Tell us what felt off, if you want."
              />
              <div class="form-text">Keep it brief. This is optional.</div>
            </div>

            <div v-if="localError || errorMessage" class="alert alert-danger py-2 px-3 small mb-0">
              {{ localError || errorMessage }}
            </div>
            <div v-else-if="actionMessage" class="alert alert-info py-2 px-3 small mb-0">
              {{ actionMessage }}
            </div>
          </div>
          <div class="modal-footer border-0 p-3 bg-body-tertiary d-flex justify-content-between align-items-center">
            <template v-if="previewMode">
              <button class="btn btn-outline-secondary" :disabled="submitting" @click="$emit('close')">
                Close
              </button>
              <div class="ms-auto d-flex flex-wrap gap-2">
                <button class="btn btn-outline-primary" :disabled="previewActionsDisabled" @click="copyPreviewDetails">
                  Copy report details
                </button>
                <button class="btn btn-danger" :disabled="previewActionsDisabled || !hasPreviewIssueUrl" @click="openPreviewIssue">
                  Open GitHub issue
                </button>
              </div>
            </template>
            <template v-else>
              <button class="btn btn-outline-secondary" :disabled="submitting" @click="$emit('close')">
                Cancel
              </button>
              <button class="btn btn-danger" :disabled="submitDisabled" @click="submitReport">
                {{ submitting ? 'Submitting...' : 'Submit report' }}
              </button>
            </template>
          </div>
        </div>
      </div>
    </div>
  </Transition>
</template>

